import React, { useState } from "react";
import Header from "../components/cinebridge/Header";
import HeroSection from "../components/cinebridge/HeroSection";
import WhySection from "../components/cinebridge/WhySection";
import DemoLicenseModal from "../components/cinebridge/DemoLicenseModal";

export default function CineBridgeLandingPage() {
  const [isModalOpen, setIsModalOpen] = useState(false);

  return (
    <>
      <Header onOpenDemo={() => setIsModalOpen(true)} />

      <main>
        <HeroSection onOpenDemo={() => setIsModalOpen(true)} />
        <WhySection onOpenDemo={() => setIsModalOpen(true)} />
      </main>

      <DemoLicenseModal open={isModalOpen} onClose={() => setIsModalOpen(false)} />
    </>
  );
}
